INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary, what_it_is, why_it_matters,
  why_it_goes_here, programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name,
  e.card_summary,
  COALESCE(e.description, e.name),
  'Builds force production and tissue tolerance to support safer, more powerful Output over time.',
  CASE e.phase_subrole
    WHEN 'squat_knee_dominant_strength' THEN 'Belongs in Squat / Knee-Dominant Strength — builds lower-body force through squat, lunge, and step patterns.'
    WHEN 'hinge_posterior_chain_strength' THEN 'Belongs in Hinge / Posterior-Chain Strength — hip extension and hamstring/glute force capacity.'
    WHEN 'upper_body_push_strength' THEN 'Belongs in Upper-Body Push Strength — pressing and hand-support capacity.'
    WHEN 'pull_hang_grip_strength' THEN 'Belongs in Pull, Hang & Grip Strength — pulling, hanging, and grip tolerance.'
    WHEN 'carry_trunk_loaded_bracing_strength' THEN 'Belongs in Carry / Trunk / Loaded-Bracing Strength — bracing under external load.'
    WHEN 'tissue_capacity_isometric_eccentric_accessory' THEN 'Belongs in Tissue Capacity — targeted isometric, eccentric, and accessory tolerance work.'
    ELSE 'Place in Capacity after Output — progressive strength with full rest.'
  END,
  'Use progressive overload with full rest between sets. Stop grinding reps; add load or complexity when technique stays clean.',
  'Do not use short-rest circuits or place heavy Capacity before Output unless strength-priority session.',
  'Youth: mastery and supervision over max load. Scale ROM, load, and volume by tissue tolerance.'
FROM coaching.exercise e
WHERE e.slug IN ('goblet-squat', 'box-squat', 'front-squat-db-kb-barbell', 'split-squat', 'rear-foot-elevated-split-squat', 'reverse-lunge', 'step-up', 'lateral-lunge-loaded', 'loaded-cossack-squat', 'heavy-sled-push-sled-drive-march', 'kettlebell-deadlift-trap-bar-deadlift', 'romanian-deadlift', 'single-leg-romanian-deadlift', 'hip-thrust-loaded-glute-bridge', 'good-morning-light-technical', 'hamstring-slider-curl', 'nordic-hamstring-eccentric', 'back-extension-hip-extension', 'incline-push-up', 'push-up', 'tempo-eccentric-push-up', 'dumbbell-kettlebell-floor-press', 'dumbbell-bench-press', 'half-kneeling-single-arm-press', 'pike-push-up-box-pike-push-up', 'dip-support-ring-support-hold', 'ring-row-trx-row', 'inverted-row', 'one-arm-dumbbell-row', 'band-cable-row', 'assisted-pull-up', 'eccentric-pull-up-chin-up-negative', 'pull-up-chin-up', 'scapular-pull-up', 'dead-hang-active-hang', 'rope-climb-foot-lock-pull-towel-pull', 'farmer-carry', 'suitcase-carry', 'front-rack-carry', 'bear-hug-sandbag-carry', 'zercher-carry', 'overhead-carry', 'pallof-press-pallof-hold', 'tall-kneeling-cable-band-chop', 'spanish-squat-isometric', 'split-squat-isometric-hold', 'copenhagen-plank-short-lever', 'tibialis-raise', 'seated-soleus-raise-bent-knee-calf-raise', 'wrist-forearm-capacity-series')
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

